import 'package:flutter/material.dart';
import 'package:flutter_payments/flutter_payments.dart';
import 'package:flutter_wallet/flutter_wallet.dart';

class PaymentProcessor {
  final FlutterPayments _flutterPayments = FlutterPayments();
  final FlutterWallet _flutterWallet = FlutterWallet();

  Future<void> processPayment(String paymentMethod, double amount) async {
    if (paymentMethod == 'card') {
      await _flutterPayments.processCardPayment(amount);
    } else if (paymentMethod == 'wallet') {
      await _flutterWallet.processWalletPayment(amount);
    }
  }
